python - <<'PY'
import csv, json, re
from collections import Counter, defaultdict
from datetime import datetime, date, timedelta

api_path='day08/api_requests_raw.csv'
ua_path='day08/user_activity_raw.json'

# ---------- API REQUESTS CHECKS ----------
api_rows=[]
with open(api_path,newline='') as f:
    r=csv.DictReader(f)
    api_fields=r.fieldnames
    for i,row in enumerate(r, start=2):  # header line is 1
        api_rows.append((i,row))

api_issues=[]
required_api_fields=['timestamp','endpoint','status_code','response_ms']
missing_fields=[f for f in required_api_fields if f not in (api_fields or [])]
if missing_fields:
    api_issues.append(('schema','error',f"Missing required columns: {missing_fields}"))

fmt='%a %b %d %H:%M:%S'
parsed_ts=0
bad_ts=[]
missing_ts=0
missing_endpoint=0
bad_status=[]
bad_resp=[]
neg_resp=[]
endpoint_pattern=re.compile(r'^/\S+')

status_counts=Counter()
endpoint_counts=Counter()

for line,row in api_rows:
    # timestamp
    ts=row.get('timestamp')
    if ts in (None,''):
        missing_ts+=1
    else:
        try:
            datetime.strptime(ts, fmt)
            parsed_ts+=1
        except Exception as e:
            bad_ts.append((line, ts))
    # endpoint
    ep=row.get('endpoint')
    if ep in (None,''):
        missing_endpoint+=1
    elif not endpoint_pattern.match(ep):
        api_issues.append(('format','warn',f"Line {line}: suspicious endpoint format: {ep!r}"))
    # status_code
    sc=row.get('status_code')
    try:
        sc_i=int(sc)
        if sc_i<100 or sc_i>599:
            bad_status.append((line, sc))
        else:
            status_counts[sc_i]+=1
    except Exception:
        bad_status.append((line, sc))
    # response_ms
    rm=row.get('response_ms')
    try:
        rm_f=float(rm)
        if rm_f<0:
            neg_resp.append((line, rm))
        if rm_f>120000:
            bad_resp.append((line, rm))
    except Exception:
        bad_resp.append((line, rm))
    if ep:
        endpoint_counts[ep]+=1

# duplicates: exact match across key fields
seen=set(); dup_lines=[]
for line,row in api_rows:
    key=(row.get('timestamp'),row.get('endpoint'),row.get('status_code'),row.get('response_ms'))
    if key in seen:
        dup_lines.append(line)
    else:
        seen.add(key)

if missing_ts:
    api_issues.append(('completeness','error',f"Missing timestamp in {missing_ts} row(s)."))
if bad_ts:
    api_issues.append(('validity','error',f"Unparseable timestamp in {len(bad_ts)} row(s): e.g. line {bad_ts[0][0]} value {bad_ts[0][1]!r}"))
if missing_endpoint:
    api_issues.append(('completeness','error',f"Missing endpoint in {missing_endpoint} row(s)."))
if bad_status:
    api_issues.append(('validity','error',f"Invalid status_code in {len(bad_status)} row(s): e.g. line {bad_status[0][0]} value {bad_status[0][1]!r}"))
if bad_resp:
    api_issues.append(('validity','error',f"Invalid/outlier response_ms in {len(bad_resp)} row(s): e.g. line {bad_resp[0][0]} value {bad_resp[0][1]!r}"))
if neg_resp:
    api_issues.append(('validity','error',f"Negative response_ms in {len(neg_resp)} row(s): e.g. line {neg_resp[0][0]} value {neg_resp[0][1]!r}"))
if dup_lines:
    api_issues.append(('uniqueness','warn',f"Detected {len(dup_lines)} potential duplicate row(s) (exact matches), e.g. line {dup_lines[0]}"))

# ---------- USER ACTIVITY CHECKS ----------
with open(ua_path) as f:
    ua=json.load(f)

ua_issues=[]
if not isinstance(ua, list):
    ua_issues.append(('schema','error',f"Root should be a list, got {type(ua).__name__}"))

required_ua_fields=['user_id','last_login','session_count','active_days']
missing_any=0
user_ids=[]

ref=date(2026,3,25)
weekday_map={'monday':0,'tuesday':1,'wednesday':2,'thursday':3,'friday':4,'saturday':5,'sunday':6}

def parse_last_login(s:str):
    s=s.strip().lower()
    if s=='today':
        return ref
    if s=='yesterday':
        return ref - timedelta(days=1)
    if s.endswith('day ago') or s.endswith('days ago'):
        n=int(s.split()[0])
        return ref - timedelta(days=n)
    if s.endswith('weeks ago') or s.endswith('week ago'):
        n=int(s.split()[0])
        return ref - timedelta(days=7*n)
    if s.startswith('last '):
        wd=s.split('last ',1)[1].strip()
        wd_num=weekday_map[wd]
        delta=(ref.weekday()-wd_num) % 7
        if delta==0:
            delta=7
        return ref - timedelta(days=delta)
    raise ValueError('unrecognized')

bad_last_login=[]
bad_session=[]
bad_active_days=[]

for idx,item in enumerate(ua):
    if not isinstance(item, dict):
        ua_issues.append(('schema','error',f"Item {idx} is not an object (got {type(item).__name__})"))
        continue
    for k in required_ua_fields:
        if k not in item:
            missing_any += 1
            ua_issues.append(('completeness','error',f"Item {idx} missing field {k}"))
            break
    uid=item.get('user_id')
    if uid:
        user_ids.append(uid)
    # last_login
    try:
        parse_last_login(item.get('last_login',''))
    except Exception:
        bad_last_login.append((idx, item.get('last_login')))
    # session_count
    try:
        sc=int(item.get('session_count'))
        if sc < 0:
            bad_session.append((idx, item.get('session_count')))
    except Exception:
        bad_session.append((idx, item.get('session_count')))
    # active_days
    try:
        ad=int(item.get('active_days'))
        if ad < 0 or ad > 7:
            bad_active_days.append((idx, item.get('active_days')))
    except Exception:
        bad_active_days.append((idx, item.get('active_days')))

uid_counts=Counter(user_ids)
dup_uids=[u for u,c in uid_counts.items() if c>1]

if bad_last_login:
    ua_issues.append(('validity','error',f"Unparseable last_login in {len(bad_last_login)} user(s): e.g. item {bad_last_login[0][0]} value {bad_last_login[0][1]!r}"))
if bad_session:
    ua_issues.append(('validity','error',f"Invalid session_count in {len(bad_session)} user(s): e.g. item {bad_session[0][0]} value {bad_session[0][1]!r}"))
if bad_active_days:
    ua_issues.append(('validity','warn',f"Suspicious active_days (expected 0-7) in {len(bad_active_days)} user(s): e.g. item {bad_active_days[0][0]} value {bad_active_days[0][1]!r}"))
if dup_uids:
    ua_issues.append(('uniqueness','error',f"Duplicate user_id(s) found: {dup_uids}"))

# ---------- REPORT ----------
now=datetime.now().astimezone().isoformat()

def sev_rank(sev):
    return {'error':2,'warn':1,'info':0}.get(sev,0)

api_issues_sorted=sorted(api_issues, key=lambda x:-sev_rank(x[1]))
ua_issues_sorted=sorted(ua_issues, key=lambda x:-sev_rank(x[1]))

def format_issues(issues):
    if not issues:
        return "- No issues detected."
    out=[]
    for cat,sev,msg in issues:
        out.append(f"- **{sev.upper()}** [{cat}] {msg}")
    return "\n".join(out)

api_total=len(api_rows)
ua_total=len(ua) if isinstance(ua,list) else 0

md=f"""# Day08 Data Quality Report

- **generated_at**: {now}
- **files_checked**:
  - `{api_path}`
  - `{ua_path}`

## 1) API Requests Raw (`api_requests_raw.csv`)

### Quick Stats
- Total rows: **{api_total}**
- Columns: **{api_fields}**
- Parseable timestamps: **{parsed_ts}/{api_total}**
- Unique endpoints: **{len(endpoint_counts)}**
- Status code distribution (top): **{dict(status_counts.most_common(5))}**

### Issues
{format_issues(api_issues_sorted)}

## 2) User Activity Raw (`user_activity_raw.json`)

### Quick Stats
- Total users: **{ua_total}**
- Required fields: **{required_ua_fields}**
- Duplicate user_id: **{len(dup_uids)}**

### Issues
{format_issues(ua_issues_sorted)}

## Recommendations / Next Steps
- Standardize timestamps to ISO-8601 with timezone (e.g. `2026-03-25T10:12:07-04:00`) to avoid year ambiguity in parsing.
- Define explicit timeout criteria in the raw logs (e.g. a boolean `timed_out`) instead of inferring from `response_ms`.
- For `user_activity_raw.json`, consider storing `last_login` as an absolute date/time rather than relative phrases (e.g. `last Friday`).
"""

out_path='day08/20260325_data_quality_report.md'
with open(out_path,'w') as f:
    f.write(md)

print('wrote', out_path)
PY
